   ) ;
ALTER TABLE "DIRKSPZM32"."RS232_CLIENT_CFG" ADD CONSTRAINT "PK_RS232_CLIENT_CFG" PRIMARY KEY ("SID", "FIRMA_NR", "HOSTNAME", "APP_EXENAME", "INSTANCE_ID", "COMPORT")
